import base64
import json
import logging
from typing import Any, Dict

logging.basicConfig(level=logging.INFO)


def _process_batch_job(job: Any) -> Dict[str, Any]:
    if isinstance(job, dict):
        job_id = job.get("job_id")
        tasks = job.get("tasks", [])
        logging.info("Processing job_id=%s task_count=%s", job_id, len(tasks))
        results = []
        for index, task in enumerate(tasks):
            results.append(
                {
                    "task_index": index,
                    "status": "processed",
                    "task": task,
                }
            )
        return {
            "job_id": job_id,
            "status": "completed",
            "results": results,
        }

    if isinstance(job, list):
        logging.info("Processing list job with %s items", len(job))
        return {
            "status": "completed",
            "results": [{"item": item, "status": "processed"} for item in job],
        }

    logging.info("Processing generic job of type %s", type(job).__name__)
    return {
        "status": "completed",
        "result": str(job),
    }


def pubsub_batch_processor(event: Dict[str, Any], context: Any) -> None:
    if "data" not in event:
        logging.warning("Pub/Sub message missing data field")
        return

    try:
        raw_data = base64.b64decode(event["data"])
        payload = json.loads(raw_data.decode("utf-8"))
    except Exception as exc:
        logging.exception("Failed to decode Pub/Sub message: %s", exc)
        raise

    result = _process_batch_job(payload)
    logging.info("Batch job processed successfully: %s", json.dumps(result))